mapper.select:
SELECT

FROM ai_business_quantity_balance
WHERE tenant_id = #{tenantId}
  AND account_code = #{accountCode}
  AND item_code = #{itemCode}
  AND dimension_key = #{dimensionKey}
LIMIT 1

mapper.update:
UPDATE ai_business_quantity_balance
SET quantity = quantity + #{quantity},
    update_time = NOW()
WHERE tenant_id = #{tenantId}
  AND account_code = #{accountCode}
  AND item_code = #{itemCode}
  AND dimension_key = #{dimensionKey}
  AND status = 1

UPDATE ai_business_quantity_balance
SET quantity = quantity - #{quantity},
    update_time = NOW()
WHERE tenant_id = #{tenantId}
  AND account_code = #{accountCode}
  AND item_code = #{itemCode}
  AND dimension_key = #{dimensionKey}
  AND status = 1
  AND quantity - locked_quantity >= #{quantity}

UPDATE ai_business_quantity_balance
SET locked_quantity = locked_quantity + #{quantity},
    update_time = NOW()
WHERE tenant_id = #{tenantId}
  AND account_code = #{accountCode}
  AND item_code = #{itemCode}
  AND dimension_key = #{dimensionKey}
  AND status = 1
  AND quantity - locked_quantity >= #{quantity}

UPDATE ai_business_quantity_balance
SET locked_quantity = locked_quantity - #{quantity},
    update_time = NOW()
WHERE tenant_id = #{tenantId}
  AND account_code = #{accountCode}
  AND item_code = #{itemCode}
  AND dimension_key = #{dimensionKey}
  AND status = 1
  AND locked_quantity >= #{quantity}

UPDATE ai_business_quantity_balance
SET quantity = quantity - #{quantity},
    locked_quantity = locked_quantity - #{quantity},
    update_time = NOW()
WHERE tenant_id = #{tenantId}
  AND account_code = #{accountCode}
  AND item_code = #{itemCode}
  AND dimension_key = #{dimensionKey}
  AND status = 1
  AND quantity >= #{quantity}
  AND locked_quantity >= #{quantity}
